import { getScaledSymbolSize } from './get-scaled-symbol-size.js';

export const createBitmapConfigOptions = (
  containerSize?: number,
): ImageBitmapOptions => {
  const squareSize =
    getScaledSymbolSize(containerSize) ?? getScaledSymbolSize();

  return {
    resizeHeight: squareSize,
    resizeWidth: squareSize,
    resizeQuality: 'high',
  };
};
